codeTemplate:
# myservice 도메인 정의
type myservice, domain;
type myservice_exec, exec_type, file_type;

# init에서 myservice로의 도메인 전환 (매크로 사용)
___(myservice)

# custom_daemon.te

# 도메인 및 실행 파일 타입 선언
type custom_daemon, domain;
type custom_daemon_exec, ___, file_type;

# init으로부터 도메인 전환
init_daemon_domain(custom_daemon)

# Binder IPC 사용 허용
___(custom_daemon)

# 자체 데이터 디렉토리 접근 허용
type custom_daemon_data_file, file_type, data_file_type;
allow custom_daemon custom_daemon_data_file:dir create_dir_perms;
allow custom_daemon custom_daemon_data_file:file ___;

# untrusted_app이 system_data_file에 직접 쓰기 금지
___ untrusted_app system_data_file:file { write append };

# untrusted_app이 exec_type 파일을 실행하는 것을 금지
neverallow untrusted_app ___:file execute;

# untrusted_app이 커널 모듈을 로드하는 것을 금지
neverallow untrusted_app self:capability ___;
